def composition(layoutA, layoutB):
    """Return the layout equivalent to applying layoutB, then layoutA."""
    # Case 1: B is None
    if layoutB is None:
        return layoutA

    # Case 2: B is an integer
    if is_int(layoutB):
        return composition(layoutA, Layout(layoutB))

    # Case 3: B is a tuple
    if is_tuple(layoutB):
        result = []
        for i, b in enumerate(layoutB):
            if b is None:
                result.append(layoutA[i])
            else:
