```python
def _composition_impl(lhs_shape, lhs_stride, rhs_shape, rhs_stride):
    """Core composition algorithm."""
    # Case: RHS shape is tuple → right-distributivity
    if is_tuple(rhs_shape):
        assert is_tuple(rhs_stride)
        result = []
        for i in range(len(rhs_shape)):
            result.append(_composition_impl(lhs_shape, lhs_stride, rhs_shape[i], rhs_stride[i]))
        return make_layout(tuple(result))

    # Case: RHS stride is 0
    if rhs_stride == 0:
        return Layout(rhs_shape, rhs_stride)

    # Case: LHS shape is integral (rank-1 after coalescing)
    if not is_tuple(lhs_shape):
        return Layout(rhs_shape, rhs_stride * lhs_stride)

    # General case: LHS is tuple, RHS is integral
    R = len(lhs_shape)

    result_shape = ()
    result_stride = ()
    rest_shape = rhs_shape
    rest_stride = rhs_stride

    for i in range(R - 1):
        curr_shape = lhs_shape[i]
        curr_stride = lhs_stride[i]

        next_shape = ceil_div(curr_shape, abs(rest_stride))
        next_stride = ceil_div(abs(rest_stride), curr_shape) * signum(rest_stride)

        if next_shape == 1 or rest_shape == 1:
            # Skip, don't add a mode
            # Update rest_stride only
            rest_stride = next_stride
        else:
            new_shape = min(next_shape, rest_shape)
            result_shape = result_shape + (new_shape,)
            result_stride = result_stride + (rest_stride * curr_stride,)
            rest_shape = rest_shape // new_shape
            rest_stride = next_stride

    if len(result_shape) == 0:
        return Layout(rest_shape, rest_stride * lhs_stride[R - 1])
    elif rest_shape == 1:
        return Layout(result_shape, result_stride)
    else:
        result_shape = result_shape + (rest_shape,)
        result_stride = result_stride + (rest_stride * lhs_stride[R - 1],)
        return Layout(result_shape, result_stride)
```

