def composition(layoutA, layoutB):
    """Return the layout equivalent to applying layoutB, then layoutA."""
    # Case 1: B is None
    if layoutB is None:
        return layoutA

    # Case 2: B is an integer: treat as Layout(layoutB)
    if is_int(layoutB):
        return composition(layoutA, Layout(layoutB))

    # Case 3: B is a tuple: compose modes independently
    if is_tuple(layoutB):
        modes = []
        for i in range(len(layoutA)):
            if i < len(layoutB) and layoutB[i] is not None:
                modes.append(composition(layoutA[i], layoutB[i]))
            else:
                modes.append(layoutA[i])
        return make_layout(tuple(modes))

    # At this point, layoutB is a Layout

    # Case 4: B.shape is hierarchical
    if is_tuple(layoutB.shape):
        A_c = coalesce(layoutA)
        modes = []
        for i in range(len(layoutB)):
            modes.append(_composition_impl(A_c.shape, A_c.stride, layoutB[i].shape, layoutB[i].stride))
        return make_layout(tuple(modes))

    # Case 5: stride-zero B
    if layoutB.stride == 0:
        return Layout(layoutB.shape, layoutB.stride)

    # Case 6: general rank-1 B
    A_c = coalesce(layoutA)
    return _composition_impl(A_c.shape, A_c.stride, layoutB.shape, layoutB.stride)
